def check_permission(user: dict, resource: dict, action: str) -> dict:
    # 1. Check revoked scopes
    for scope in user.get("revoked_scopes", []):
        if scope["resource_id"] == resource["id"] and scope["action"] == action:
            return {"allowed": False, "reason": "revoked"}

    # 2. Admin access
    if user["role"] == "admin":
        return {"allowed": True, "reason": "admin"}

    # 3. Owner access
    if user["id"] == resource["owner_id"]:
        return {"allowed": True, "reason": "owner"}

    # 4. Reviewer access
    if user["role"] == "reviewer" and action == "read":
        return {"allowed": True, "reason": "reviewer_read"}

    # 5. Team member access
    if user["role"] == "member" and action in ("read", "write") and resource["team_id"] in user.get("teams", []):
        return {"allowed": True, "reason": "member_team"}

    # 6. Default deny
    return {"allowed": False, "reason": "default_deny"}
